import { Component } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';

@Component({
  selector: 'app-reservation-form',
  templateUrl: './reservation-form.component.html',
  styleUrls: ['./reservation-form.component.css']
})
export class ReservationFormComponent {

  reservationForm: FormGroup;

  constructor(private formBuilder: FormBuilder) {
    this.reservationForm = this.formBuilder.group({
      guestName: ['', Validators.required],
      guestEmail: ['', [Validators.required, Validators.email]],
      checkInDate: ['', Validators.required],
      checkOutDate: ['', Validators.required]
    });
  }

  onSubmit() {
    if (this.reservationForm.valid) {
      console.log(this.reservationForm.value);
    }
  }
}
<form [formGroup]="reservationForm" (ngSubmit)="onSubmit()">
  <div>
    <label for="guestName">Name:</label>
    <input id="guestName" formControlName="guestName" required>
  </div>

  <div>
    <label for="guestEmail">Email:</label>
    <input id="guestEmail" formControlName="guestEmail" required type="email">
    <div *ngIf="reservationForm.get('guestEmail')?.invalid && reservationForm.get('guestEmail')?.touched">
      Please enter a valid email.
    </div>
  </div>

  <div>
    <label for="checkInDate">Check-in Date:</label>
    <input id="checkInDate" formControlName="checkInDate" required type="date">
  </div>

  <div>
    <label for="checkOutDate">Check-out Date:</label>
    <input id="checkOutDate" formControlName="checkOutDate" required type="date">
  </div>

  <button type="submit" [disabled]="reservationForm.invalid">Submit Reservation</button>
</form>
